module reg_with_clear (
  input clk,
  input clr,
  input en,
  input [7:0] data,
  output reg [7:0] q
);

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge clr or posedge dbg_halt) begin
    if (clr)
      q <= 8'b00000000;
    else if (en)
      q <= data;
  end

endmodule
